import{_ as i,o,c as r,ac as t}from"./chunks/framework.DnBnwVZk.js";const p=JSON.parse('{"title":"Dubbo源码-DubboBootstrap.start","description":"","frontmatter":{"date":"2020-04-02T00:00:00.000Z","categories":["Dubbo"],"tags":["Dubbo","源码"]},"headers":[],"relativePath":"views/java/dubbo/2020/DubboStart.md","filePath":"views/java/dubbo/2020/DubboStart.md","lastUpdated":1775654397000}'),a={name:"views/java/dubbo/2020/DubboStart.md"};function l(n,e,s,c,d,b){return o(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1585785600000"},[...e[0]||(e[0]=[t('<h1 id="dubbo源码-dubbobootstrap-start" tabindex="-1">Dubbo源码-DubboBootstrap.start <a class="header-anchor" href="#dubbo源码-dubbobootstrap-start" aria-label="Permalink to &quot;Dubbo源码-DubboBootstrap.start&quot;">​</a></h1><p>在Spring上下文refresh完成后，会广播<code>ContextRefreshed</code>事件，此时<code>DubboBootstrapApplicationListener</code>的监听被触发，调用dubboBootstrap实例的<code>start</code>方法，DubboBootStrap作为单例类，在初始化单例时，通过Dubbo特殊的SPI机制初始化了一些Extension实例</p><h2 id="_1-1-加载的插件" tabindex="-1">1.1 加载的插件 <a class="header-anchor" href="#_1-1-加载的插件" aria-label="Permalink to &quot;1.1 加载的插件&quot;">​</a></h2><ol><li>EventDispatcher:Dubbo相关事件分发，通过监听模式实现，有parallel和direct两种实现，在初始化Dispatcher实例时，会初始化EventListener</li><li>ExtensionFactory:插件实例工厂类， <ul><li>SpringExtensionFactory：从Spring上下文(BeanFactory)中加载Extension实例</li><li>SpiExtensionFactory：使用DubboSPI机制加载Extension实例</li><li>AdaptiveExtensionFactory：通过内置的AdaptiveCompiler编译为对应的Adaptive实例，来适配所有已加载的Extension的实现，遍历上述两个Factory来加载实例，其本身也是通过SPI机制来初始化的</li></ul></li><li>EventListener:Dubbo事件监听器，会被放入EventDispatcher实例 <ul><li>ServiceNameMappingListener:ServiceConfigExportedEvent时，导出ServiceMap</li><li>各种LoggingEventListener：打印Service事件日志</li><li>CustomizableServiceInstanceListener：ServiceInstancePreRegisteredEvent事件后，调用各种ServiceInstanceCustomizer</li></ul></li><li>ExecutorRepository：</li><li>FrameExt:框架相关的插件， <ul><li>ConfigManager:配置管理</li><li>Environment：Dubbo环境管理，整合Spring配置等，初始化时会调用ConfigManager插件来获取配置中心信息</li><li>ServiceRepository：注册Service，包括Provider和Consumer</li></ul></li><li>ShutdownHookCallback：shutdown的钩子</li><li>Protocol：各种rpc协议，默认为dubbo,可以查看<code>org.apache.dubbo.rpc.protocol</code>包，实际也是通过Dubbo的Compile机制编译成的Adaptive插件，<strong>注意，实际上检查各种Protocol的依赖包是在这个编译过程中进行的</strong></li><li>ProxyFactory：代理类的工厂类，默认是javassist</li><li>BuiltinServiceDetector：加载内置Service：GenericService和EchoService</li><li>DynamicConfigurationFactory:动态获取配置的工厂类，对于每一种protocol，都有对应的实现</li><li>ZookeeperTransporter：实际执行与zk的连接过程</li><li>WritableMetadataService:MetadataService，负责管理某个Service的元数据，provider侧用inMemory保存本地提供的Service，consumer侧用remote保存订阅的Provider信息</li><li>MetadataServiceExporter:负责管理ServiceConfig和MetadataService List</li></ol><h3 id="_1-2-加载配置管理器-configmanager" tabindex="-1">1.2 加载配置管理器：ConfigManager <a class="header-anchor" href="#_1-2-加载配置管理器-configmanager" aria-label="Permalink to &quot;1.2 加载配置管理器：ConfigManager&quot;">​</a></h3><ul><li>配置中心：自实现ConfigCenterConfig可以</li></ul><h3 id="_1-3-注册shutdownhook" tabindex="-1">1.3 注册ShutdownHook <a class="header-anchor" href="#_1-3-注册shutdownhook" aria-label="Permalink to &quot;1.3 注册ShutdownHook&quot;">​</a></h3><h2 id="_2-initialize" tabindex="-1">2. Initialize <a class="header-anchor" href="#_2-initialize" aria-label="Permalink to &quot;2. Initialize&quot;">​</a></h2><ol><li>加载FrameworkExt插件：加载@SPI注解的FrameworkExt接口的实现类，调用其Initialize方法，主要是Environment插件的getConfig方法来获取配置中心-dubbo.configCenter.xxx的配置</li><li>启动配置中心</li><li>如果没有配置中心，使用Registry即注册中心当作配置中心 <ul><li>prepareEnvironment: 这个过程会尝试读取配置中心的配置，由于把注册中心复用为配置中心，此时会加载注册中心相关的Ext，并尝试连接注册中心获取动态配置</li></ul></li><li>开启MetadataReport： <ol><li>调用InfraAdapter <ul><li>EnvironmentAdapter:获取OS Environment: DUBBO_LABELS=tag=pre;key=value 、JVM Options: -Denv_keys = DUBBO_KEY1, DUBBO_KEY2,放入配置</li></ul></li></ol></li><li>从远程配置中加载注册中心</li><li>校验配置：校验长度、正则表达式等</li><li>初始化MetadataService</li><li>初始化MetadataServiceExporter</li><li>注册事件监听：DubboBootstrap实例也监听了某些事件</li></ol><h2 id="_3-export-dubbo-services" tabindex="-1">3. export Dubbo Services <a class="header-anchor" href="#_3-export-dubbo-services" aria-label="Permalink to &quot;3. export Dubbo Services&quot;">​</a></h2><p>遍历ConfigManager里面的每个&quot;service&quot;配置</p><ol><li>生成对应的ServiceMetadata</li><li>ServiceRepository注册Provider，每个Provider包裹在ProviderModel里，内部包含元信息和MethodModel列表</li><li>生成Exporter和注册Exporter <ol><li>生成需要往注册中心注册的URL，URL里包含以下信息 <ul><li>Protocol，通过组合默认配置和自定义配置，决定传输协议，本机IP，端口等信息</li><li>通过从ProviderConfig里提取，决定接口，方法列表等信息</li></ul></li><li>调用ProxyFactory插件来生成Invoker，把Invoker和url包裹成Exporter，对于Provider侧，代理默认使用Javassist来生成Injvm代理，</li><li>Exporter根据URL打开本地的ExchangServer，默认使用Netty4，并进行序列化优化</li></ol></li><li>publishServiceDefinition：生成ServiceDefinition</li><li>服务发布，发布ServiceConfigExportedEvent，触发对应的Listener <ul><li>ServiceNameMapping</li></ul></li></ol><h2 id="_4-referservices" tabindex="-1">4. referServices <a class="header-anchor" href="#_4-referservices" aria-label="Permalink to &quot;4. referServices&quot;">​</a></h2>',13)])])}const v=i(a,[["render",l]]);export{p as __pageData,v as default};
